UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('1b151cfc-a9ce-496b-9d94-d1f53c69db80'::uuid, 'Le déséquilibre de la flore vaginale favorise la sécheresse, les probiotiques aident à rééquilibrer le pH et la microflore locale.'),('616cc97b-fc81-4be6-9228-ed6cd14f3a04'::uuid, 'Le sevrage tabagique s''accompagne d''un manque de nicotine, les patchs aident à délivrer une dose contrôlée pour réduire les symptômes de manque.'),('d916e1bf-5f37-4195-9a20-f4b5b5ac498f'::uuid, 'Le sevrage tabagique est difficile en raison du manque de nicotine, les patchs diffusent la nicotine pour maîtriser l''envie de fumer.'),('af85c172-a626-47e3-a7fb-4cba80feed3b'::uuid, 'Les envies subites de fumer durant le sevrage sont intenses, les gommes à la nicotine aident à bloquer rapidement le manque.'),('279f33bf-3998-4897-9ee3-744e978de217'::uuid, 'La sinusite entraîne une congestion nasale, un spray hypertonique aide à désencombrer les fosses nasales par osmose.'),('5128f8c5-3abc-4603-9cf3-1e4e644f3b83'::uuid, 'La sinusite provoque une stagnation du mucus dans les sinus, ce spray hypertonique aide à fluidifier et éliminer les sécrétions.'),('42f0dab4-a4dc-4d92-9209-1efeb5f800c6'::uuid, 'La sinusite s''accompagne de mucosités épaisses, l''inhalation de vapeur aide à fluidifier les sécrétions pour mieux respirer.'),('cad3b37b-6149-4db4-9c5a-e63b2ad5529e'::uuid, 'Les spasmes intestinaux peuvent dérégler la flore digestive, ces probiotiques aident à rééquilibrer la microflore intestinale.'),('e657b39c-fb5f-4634-95d0-bfb67a613793'::uuid, 'Les spasmes intestinaux peuvent altérer la flore digestive, ces probiotiques aident à restaurer l''équilibre de la microflore.'),('d391f062-847d-4f9f-a8c3-d5fea734e0e9'::uuid, 'Les spasmes intestinaux perturbent l''équilibre de la flore intestinale, ces probiotiques aident à soutenir la digestion.'),('705d512b-8251-49c7-ba4b-f80d18319fe6'::uuid, 'Les carences en magnésium et vitamine B6 favorisent les spasmes musculaires, ce complément aide à améliorer la fonction musculaire.'),('44306730-9cb8-4ec7-92b8-9b64b6c81e99'::uuid, 'Les spasmes musculaires entraînent une tension locale, ce spray décontractant aide à relâcher la tension musculaire.'),('b0473747-029f-4e51-876d-b48e45186447'::uuid, 'Les spasmes musculaires sont souvent soulagés par la chaleur, cette bouillotte aide à détendre les muscles contractés.'),('9cdbba30-8f18-4a60-8a42-5a04830ed743'::uuid, 'La spasmophilie est souvent liée à un déficit en magnésium, ce bisglycinate aide à améliorer la régulation nerveuse et musculaire.'),('bc743f02-39d5-4c8d-97a7-fe91bca53b69'::uuid, 'Le manque de magnésium peut exacerber la spasmophilie, ce magnésium marin + B6 aide à réguler l''équilibre neuromusculaire.'),('e5ecdf54-b73f-479f-bb72-8eac124fd9d2'::uuid, 'Les déséquilibres ioniques peuvent influencer la spasmophilie, le calcium et la vitamine D aident à réguler la fonction nerveuse et musculaire.'),('e768d9e3-374d-4daa-abb9-8fb57cb6c234'::uuid, 'La spondylarthrite provoque des douleurs inflammatoires, le baume du tigre aide à soulager localement les tensions articulaires et musculaires.'),('c944e48c-c941-4ce5-a5b1-a828c9fd87db'::uuid, 'La spondylarthrite se manifeste par des douleurs articulaires inflammatoires, la thermothérapie aide à apaiser la douleur et la raideur.'),('74256187-ec1c-4053-81fb-df29d639dae9'::uuid, 'La spondylarthrite peut causer des douleurs inflammatoires, l''Arnica Montana aide à atténuer l''inflammation et les contusions.'),('0b6ae639-3b05-41bd-9f49-54b6ff79022c'::uuid, 'Le stress consomme le magnésium, ce complément aide à réguler le système nerveux et réduire la sensation de tension.'),('d2735907-60d8-4f26-a37b-bcd46bc5ca31'::uuid, 'Le stress entraîne une suractivation nerveuse, l''Euphytose aide à apaiser le système nerveux pour favoriser la relaxation.'),('4bb2de3a-c7c6-4400-8294-618c1e98610d'::uuid, 'Le stress accroît les besoins en magnésium, le bisglycinate aide à soutenir la fonction nerveuse et réduire la fatigue.'),('5398e78e-5a76-4535-b777-882ec766d4e6'::uuid, 'Le stress peut déséquilibrer le système nerveux, le magnésium B6 aide à moduler la réponse au stress.'),('ca3370ce-7954-41c5-8430-3adf61d64128'::uuid, 'Le stress surcharge le système nerveux et hormonal, la Rhodiola aide à moduler la réponse physiologique au stress.'),('f76bb5ac-aa25-492f-a511-4e6940e9ab71'::uuid, 'Le stress chronique perturbe les systèmes d''adaptation, l''Ashwagandha aide à réguler la réponse du corps au stress.'),('51d691e7-7f2a-47a6-9412-e8eb163b689f'::uuid, 'Le stress post-traumatique peut épuiser les réserves de magnésium, ce complément aide à soutenir le fonctionnement nerveux.'),('37967c67-c416-414c-b707-5ef7bb68a355'::uuid, 'Les traumatismes perturbent le cycle de sommeil, la mélatonine aide à réguler l''horloge biologique pour retrouver un sommeil réparateur.'),('8225ba07-6bc8-4a19-8daa-fd4c47148bce'::uuid, 'Le stress post-traumatique génère de l''anxiété, l''huile essentielle de lavande aide à apaiser le système nerveux.'),('495dd666-fc2a-438e-b048-39d8bcef3bda'::uuid, 'Le surpoids est souvent lié à des apports excessifs, le konjac aide à créer une sensation de satiété pour mieux contrôler l''appétit.'),('df6535e3-0b1c-4837-be2c-f6331f55c8e2'::uuid, 'L''appétit excessif contribue au surpoids, le glucomannane de konjac aide à augmenter la sensation de satiété.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;